from enum import Enum
from typing import Dict, List, Optional, Any
from dataclasses import dataclass, field
from decimal import Decimal


class UserTier(Enum):
    GUEST = "guest"
    STANDARD = "standard"
    PREMIUM = "premium"
    ADMIN = "admin"


class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"


@dataclass
class CartItem:
    product_id: str
    name: str
    price: Decimal
    quantity: int
    available_stock: int = 1000


@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountType
    value: Decimal
    allowed_tiers: List[UserTier]
    min_purchase: Decimal = Decimal('0')
    max_discount: Optional[Decimal] = None


@dataclass
class User:
    user_id: str
    tier: UserTier
    email: str


@dataclass
class TaxRate:
    region: str
    rate: Decimal


@dataclass
class PaymentMethod:
    method_type: str
    details: Dict[str, Any]


@dataclass
class ValidationResult:
    valid: bool
    items: List[CartItem] = field(default_factory=list)
    subtotal: Decimal = Decimal('0')
    errors: List[str] = field(default_factory=list)


@dataclass
class DiscountResult:
    applied: bool
    discount_code: Optional[str] = None
    discount_amount: Decimal = Decimal('0')
    subtotal_after_discount: Decimal = Decimal('0')
    errors: List[str] = field(default_factory=list)


@dataclass
class TaxResult:
    tax_amount: Decimal = Decimal('0')
    total_with_tax: Decimal = Decimal('0')
    errors: List[str] = field(default_factory=list)


@dataclass
class PaymentResult:
    success: bool
    transaction_id: Optional[str] = None
    errors: List[str] = field(default_factory=list)


@dataclass
class OrderRecord:
    order_id: str
    user_id: str
    items: List[CartItem]
    subtotal: Decimal
    discount_amount: Decimal
    tax_amount: Decimal
    total: Decimal
    payment_transaction_id: str
    discount_code_used: Optional[str] = None


class CheckoutProcessor:
    def __init__(self):
        self.available_discount_codes: Dict[str, DiscountCode] = {}
        self.tax_rates: Dict[str, TaxRate] = {}
        
    def add_discount_code(self, discount_code: DiscountCode):
        self.available_discount_codes[discount_code.code] = discount_code
    
    def add_tax_rate(self, tax_rate: TaxRate):
        self.tax_rates[tax_rate.region] = tax_rate
    
    def validate_cart_items(self, items: List[CartItem]) -> ValidationResult:
        if not items:
            return ValidationResult(valid=False, errors=["Cart is empty"])
        
        validated_items = []
        errors = []
        subtotal = Decimal('0')
        
        for item in items:
            if item.quantity <= 0:
                errors.append(f"Invalid quantity for {item.name}")
                continue
            
            if item.price <= 0:
                errors.append(f"Invalid price for {item.name}")
                continue
            
            if item.quantity > item.available_stock:
                errors.append(f"Insufficient stock for {item.name}. Available: {item.available_stock}")
                continue
            
            validated_items.append(item)
            subtotal += item.price * item.quantity
        
        if errors:
            return ValidationResult(valid=False, items=validated_items, subtotal=subtotal, errors=errors)
        
        return ValidationResult(valid=True, items=validated_items, subtotal=subtotal)
    
    def apply_discount_code(
        self, 
        validation_result: ValidationResult, 
        user: User, 
        discount_code: Optional[str] = None
    ) -> DiscountResult:
        if not validation_result.valid:
            return DiscountResult(
                applied=False, 
                subtotal_after_discount=validation_result.subtotal,
                errors=["Cannot apply discount to invalid cart"]
            )
        
        if not discount_code:
            return DiscountResult(
                applied=False,
                subtotal_after_discount=validation_result.subtotal
            )
        
        if discount_code not in self.available_discount_codes:
            return DiscountResult(
                applied=False,
                subtotal_after_discount=validation_result.subtotal,
                errors=[f"Invalid discount code: {discount_code}"]
            )
        
        discount = self.available_discount_codes[discount_code]
        
        if user.tier not in discount.allowed_tiers:
            return DiscountResult(
                applied=False,
                subtotal_after_discount=validation_result.subtotal,
                errors=[f"User tier {user.tier.value} not allowed to use discount code {discount_code}"]
            )
        
        if validation_result.subtotal < discount.min_purchase:
            return DiscountResult(
                applied=False,
                subtotal_after_discount=validation_result.subtotal,
                errors=[f"Minimum purchase of {discount.min_purchase} required for this discount"]
            )
        
        if discount.discount_type == DiscountType.PERCENTAGE:
            discount_amount = validation_result.subtotal * (discount.value / Decimal('100'))
        else:
            discount_amount = discount.value
        
        if discount.max_discount:
            discount_amount = min(discount_amount, discount.max_discount)
        
        discount_amount = min(discount_amount, validation_result.subtotal)
        subtotal_after_discount = validation_result.subtotal - discount_amount
        
        return DiscountResult(
            applied=True,
            discount_code=discount_code,
            discount_amount=discount_amount,
            subtotal_after_discount=subtotal_after_discount
        )
    
    def calculate_tax(
        self, 
        discount_result: DiscountResult, 
        region: str
    ) -> TaxResult:
        if discount_result.errors:
            return TaxResult(errors=["Cannot calculate tax on failed discount application"])
        
        if region not in self.tax_rates:
            return TaxResult(errors=[f"Unknown tax region: {region}"])
        
        tax_rate = self.tax_rates[region]
        tax_amount = discount_result.subtotal_after_discount * tax_rate.rate
        total_with_tax = discount_result.subtotal_after_discount + tax_amount
        
        return TaxResult(
            tax_amount=tax_amount,
            total_with_tax=total_with_tax
        )
    
    def process_payment(
        self, 
        tax_result: TaxResult, 
        payment_method: PaymentMethod
    ) -> PaymentResult:
        if tax_result.errors:
            return PaymentResult(success=False, errors=["Cannot process payment on failed tax calculation"])
        
        if tax_result.total_with_tax <= 0:
            return PaymentResult(success=False, errors=["Invalid payment amount"])
        
        if payment_method.method_type not in ["credit_card", "debit_card", "paypal", "bank_transfer"]:
            return PaymentResult(success=False, errors=["Invalid payment method"])
        
        import uuid
        transaction_id = f"TXN-{uuid.uuid4().hex[:12].upper()}"
        
        return PaymentResult(success=True, transaction_id=transaction_id)
    
    def create_order_record(
        self,
        user: User,
        validation_result: ValidationResult,
        discount_result: DiscountResult,
        tax_result: TaxResult,
        payment_result: PaymentResult
    ) -> Optional[OrderRecord]:
        if not payment_result.success:
            return None
        
        import uuid
        order_id = f"ORD-{uuid.uuid4().hex[:12].upper()}"
        
        order = OrderRecord(
            order_id=order_id,
            user_id=user.user_id,
            items=validation_result.items,
            subtotal=validation_result.subtotal,
            discount_amount=discount_result.discount_amount,
            tax_amount=tax_result.tax_amount,
            total=tax_result.total_with_tax,
            payment_transaction_id=payment_result.transaction_id,
            discount_code_used=discount_result.discount_code
        )
        
        return order
    
    def checkout(
        self,
        user: User,
        items: List[CartItem],
        region: str,
        payment_method: PaymentMethod,
        discount_code: Optional[str] = None
    ) -> Dict[str, Any]:
        step1 = self.validate_cart_items(items)
        if not step1.valid:
            return {
                "success": False,
                "step": "validation",
                "errors": step1.errors
            }
        
        step2 = self.apply_discount_code(step1, user, discount_code)
        if step2.errors:
            return {
                "success": False,
                "step": "discount",
                "errors": step2.errors
            }
        
        step3 = self.calculate_tax(step2, region)
        if step3.errors:
            return {
                "success": False,
                "step": "tax",
                "errors": step3.errors
            }
        
        step4 = self.process_payment(step3, payment_method)
        if not step4.success:
            return {
                "success": False,
                "step": "payment",
                "errors": step4.errors
            }
        
        order = self.create_order_record(user, step1, step2, step3, step4)
        if not order:
            return {
                "success": False,
                "step": "order_creation",
                "errors": ["Failed to create order record"]
            }
        
        return {
            "success": True,
            "order": order,
            "details": {
                "subtotal": str(step1.subtotal),
                "discount_applied": step2.applied,
                "discount_amount": str(step2.discount_amount),
                "tax_amount": str(step3.tax_amount),
                "total": str(step3.total_with_tax)
            }
        }


